var e=[{id:`L2_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`하핫 제법이잖아?`,JPN:` ははっ。やるじゃない。`,ENG:`Hah hah, not bad!`,TWN:`哈哈，身手不錯嘛？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SPEAKER_JUNIOR_NULL_NULL`,text:{KOREA:`후배를 상대로 진심으로 싸우는 선배라니!`,JPN:` 後輩相手に先輩が本気になるなんて！`,ENG:`A senior who doesn't go easy on juniors?!`,TWN:`身為前輩，竟然真的對後輩絲毫不留情面！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L6_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`와… 악당이시네요…`,JPN:` うわあ……悪党だ……`,ENG:`Wow... You really are evil...`,TWN:`哇…你是壞姊姊…`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L8_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`두명이서 덤비는 게 더 악당 같거든?!`,JPN:` 二人でかかってきている方が悪党だからね？`,ENG:`But the two of you ganging up on me isn't?!`,TWN:`你們二個對我一個才壞吧？！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`게다가 건성으로 상대하는 게 더 실례 아니겠어?`,JPN:` それに手を抜かれる方が失礼に思うでしょ？`,ENG:`Plus, it's rude to fight half-heartedly, don't you think so too?`,TWN:`而且我不認真打的話，對你們才更失禮吧？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SPEAKER_JUNIOR_NULL_NULL`,text:{KOREA:`엄청난 핑계다!`,JPN:` 酷い言い訳！`,ENG:`What an excuse!`,TWN:`根本是藉口！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L13_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`핑계다…`,JPN:` 絶対言い訳だ……`,ENG:`You and your excuses...`,TWN:`是藉口…`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L15_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`시끄러웟!`,JPN:` うるさいわね！`,ENG:`Oh, shut it!`,TWN:`少廢話！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`라고 말한 사이에 빈틈이닷!`,JPN:` と言っていたら、隙あり！`,ENG:`And I see an opening just as I say it!`,TWN:`在你們囉哩叭唆的時候我又抓到破綻囉！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`꺄앗!`,JPN:` きゃあっ！`,ENG:`Kyaah!`,TWN:`哎呀！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`하핫, 이거거든! 예전의 나를 생각하면 오산이야!`,JPN:` ははっ、どうよ！　以前の私と同じだと思ったら大間違いよ！`,ENG:`Hah hah, that's it! You'd better not think you're going up against the old me!`,TWN:`哈哈！知道厲害了吧？我已經不是以前那個我了！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SPEAKER_JUNIOR_NULL_NULL`,text:{KOREA:`지, 진짜로 비겁하잖아!`,JPN:` な、なんて卑怯な！`,ENG:`W-what a totally cowardly move!`,TWN:`你…你真的很卑鄙欸！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`SPEAKER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`이게 바로 선배를 무시한 대가다! 선물 대신이라 생각하라고!`,JPN:` これが先輩をバカにした報いよ！　プレゼント代わりに受け取りなさい！`,ENG:`That was for making fun of your senior! Think of that as your gift instead!`,TWN:`誰叫你們敢瞧不起前輩！這個教訓就是你們禮物！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`아얏…!`,JPN:` 痛っ……！`,ENG:`Ow...!`,TWN:`哎呀…！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`어, 어디서 날라온거지?`,JPN:` ど、どこから飛んできたの？`,ENG:`W-where did that come from?`,TWN:`誰…誰扔我！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`TWINTAIL_MAGICIAN_NPC_NULL`,text:{KOREA:`아얏! 아야야!`,JPN:` いたっ！　いたたたっ！`,ENG:`Ow! Ouch!!`,TWN:`哎呀！哎呀！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`TWINTAIL_MAGICIAN_NPC_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};